const email = $input.first().json;

// Gmail node uses capital "From", "Subject", "To"
const from = email.From || email.from || email.headers?.from || '';
const subject = email.Subject || email.subject || '(No Subject)';
const body = email.text || email.snippet || '';
const messageId = email.id || '';
const threadId = email.threadId || '';

// Parse email address
let guestName = '';
let guestEmail = '';

const angleMatch = from.match(/"?([^"<]+)"?\s*<([^>]+)>/);
const plainMatch = from.match(/[\w.-]+@[\w.-]+\.\w+/);

if (angleMatch) {
  guestName = angleMatch[1].trim();
  guestEmail = angleMatch[2].trim();
} else if (plainMatch) {
  guestEmail = plainMatch[0].trim();
  guestName = guestEmail.split('@')[0];
} else {
  guestEmail = from.trim();
  guestName = 'Guest';
}

// Clean body
const cleanBody = body
  .split('\nOn ')[0]
  .split('\n>')[0]
  .trim()
  .substring(0, 1000);

return [{
  json: {
    channel: 'email',
    guestName: guestName || 'Guest',
    guestEmail: guestEmail,
    subject: subject,
    message: cleanBody,
    messageId: messageId,
    threadId: threadId,
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
const subject = data.subject.toLowerCase();
const message = data.message.toLowerCase();

// Detect language
let detectedLang = 'English';
if (message.match(/\b(ciao|buongiorno|buonasera|vorrei|camera|prenotare|grazie)\b/i)) {
  detectedLang = 'Italian';
} else if (message.match(/\b(mirëdita|mirëmbrëma|dhomë|rezervim|faleminderit|çmim)\b/i)) {
  detectedLang = 'Albanian';
} else if (message.match(/\b(hola|buenos|habitación|reservar|gracias|precio)\b/i)) {
  detectedLang = 'Spanish';
} else if (message.match(/\b(hallo|guten|zimmer|buchen|danke|preis)\b/i)) {
  detectedLang = 'German';
} else if (message.match(/\b(bonjour|bonsoir|chambre|réserver|merci|prix)\b/i)) {
  detectedLang = 'French';
}

// Detect intent
let intent = 'general_inquiry';
if (subject.match(/book|reserv|room|stay|availab/i) || message.match(/book|reserv|room|stay|availab|check.?in|check.?out/i)) {
  intent = 'booking_inquiry';
} else if (subject.match(/cancel/i) || message.match(/cancel/i)) {
  intent = 'cancellation';
} else if (subject.match(/price|rate|cost|how much/i) || message.match(/price|rate|cost|how much|tariff/i)) {
  intent = 'pricing_inquiry';
} else if (subject.match(/amenit|facilit|pool|spa|restaur/i) || message.match(/amenit|facilit|pool|spa|restaur|gym/i)) {
  intent = 'amenities_inquiry';
} else if (subject.match(/direction|location|address|how to get/i) || message.match(/direction|location|address|how to get|transport/i)) {
  intent = 'directions_inquiry';
}

return [{
  json: {
    ...data,
    detectedLang,
    intent
  }
}];

const geminiResponse = $input.first().json;
const emailData = $('Detect Language and Intent').first().json;

const aiText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';

const fallback = `Dear ${emailData.guestName},

Thank you for contacting Hotel Adriatica! We would be delighted to assist you with your booking.

To complete your reservation, please provide:

1. Check-in date?
2. Check-out date?
3. Number of guests?
4. Room preference?
   - Standard Room: €80/night
   - Deluxe Lake View: €120/night
   - Junior Suite: €180/night
   - Penthouse Suite: €300/night

Warm regards,
Sofia | AI Concierge | Hotel Adriatica
+355 22 123 456 | info@hoteladriatica.al`;

const plainText = (aiText && aiText.trim().length > 80) ? aiText.trim() : fallback;

// Convert plain text to HTML
const htmlBody = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#333;">' 
  + plainText.replace(/\n\n/g, '</p><p>').replace(/\n/g, '<br>') 
  + '</p></div>';

const originalSubject = emailData.subject || '';
const replySubject = originalSubject.startsWith('Re:') ? originalSubject : `Re: ${originalSubject}`;

return [{
  json: {
    replyBody: htmlBody,
    replySubject: replySubject,
    toEmail: emailData.guestEmail,
    guestName: emailData.guestName,
    guestEmail: emailData.guestEmail,
    originalMessage: emailData.message,
    intent: emailData.intent,
    detectedLang: emailData.detectedLang,
    threadId: emailData.threadId,
    timestamp: emailData.timestamp
  }
}];

const d = $('Detect Language and Intent').first().json;

const prompt = `You are Sofia, AI concierge of Hotel Adriatica, Shkodër Albania.

ROOMS: Standard €80, Deluxe Lake View €120, Junior Suite €180, Penthouse €300/night. Breakfast €15. Pool, Spa, Restaurant 7AM-11PM, Free WiFi. No pets. Cancellation free 48h before. Contact: +355 22 123 456.

Guest Name: ${d.guestName}
Message: ${d.message}
Language: ${d.detectedLang}
Intent: ${d.intent}

Instructions: Reply in guest language. If booking_inquiry, ask these 4 questions clearly numbered:
1. Check-in date?
2. Check-out date?
3. Number of guests?
4. Room preference? (Standard €80, Deluxe €120, Junior Suite €180, Penthouse €300)

Max 250 words. Warm professional tone. End with: Warm regards, Sofia | AI Concierge | Hotel Adriatica | +355 22 123 456`;

return [{
  json: {
    ...d,
    geminiBody: JSON.stringify({
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig: { maxOutputTokens: 1024, temperature: 0.7 }
    })
  }
}];
